import{_ as e,c as o,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Funcionalidades Principales: Tres Capacidades | opencode-dcp","description":"Aprende las tres funcionalidades principales de opencode-dcp: estrategias de poda automática, herramientas impulsadas por LLM y comandos Slash. Domina estas funciones para maximizar el potencial de optimización de tokens.","frontmatter":{"title":"Funcionalidades Principales: Tres Capacidades | opencode-dcp","sidebarTitle":"Desbloquear Tres Capacidades","subtitle":"Funcionalidades Principales: Tres Capacidades","description":"Aprende las tres funcionalidades principales de opencode-dcp: estrategias de poda automática, herramientas impulsadas por LLM y comandos Slash. Domina estas funciones para maximizar el potencial de optimización de tokens.","order":20},"headers":[],"relativePath":"es/Opencode-DCP/opencode-dynamic-context-pruning/platforms/index.md","filePath":"es/Opencode-DCP/opencode-dynamic-context-pruning/platforms/index.md"}'),t={name:"es/Opencode-DCP/opencode-dynamic-context-pruning/platforms/index.md"};function n(d,a,r,c,l,p){return s(),o("div",null,[...a[0]||(a[0]=[i(`<h1 id="funcionalidades-principales" tabindex="-1">Funcionalidades Principales <a class="header-anchor" href="#funcionalidades-principales" aria-label="Permalink to &quot;Funcionalidades Principales&quot;">​</a></h1><p>Este capítulo explora en profundidad las tres capacidades principales de DCP: estrategias de poda automática, herramientas impulsadas por LLM y comandos Slash. Al dominar estas funcionalidades, podrás aprovechar al máximo el potencial de optimización de tokens de DCP.</p><h2 id="contenido-del-capitulo" tabindex="-1">Contenido del Capítulo <a class="header-anchor" href="#contenido-del-capitulo" aria-label="Permalink to &quot;Contenido del Capítulo&quot;">​</a></h2><div class="grid-cards"><h3 id="estrategias-de-poda-automatica" tabindex="-1"><a href="./auto-pruning/">Estrategias de Poda Automática</a> <a class="header-anchor" href="#estrategias-de-poda-automatica" aria-label="Permalink to &quot;[Estrategias de Poda Automática](./auto-pruning/)&quot;">​</a></h3><p>Explora en profundidad cómo funcionan las tres estrategias automáticas de DCP: estrategia de deduplicación, estrategia de sobrescritura y estrategia de limpieza de errores. Conoce las condiciones de activación y escenarios de uso de cada estrategia.</p><h3 id="herramientas-de-poda-impulsadas-por-llm" tabindex="-1"><a href="./llm-tools/">Herramientas de Poda Impulsadas por LLM</a> <a class="header-anchor" href="#herramientas-de-poda-impulsadas-por-llm" aria-label="Permalink to &quot;[Herramientas de Poda Impulsadas por LLM](./llm-tools/)&quot;">​</a></h3><p>Entiende cómo la IA llama autónomamente a las herramientas <code>discard</code> y <code>extract</code> para optimizar el contexto. Esta es la funcionalidad más inteligente de DCP, permitiendo que la IA participe activamente en la gestión del contexto.</p><h3 id="uso-de-comandos-slash" tabindex="-1"><a href="./commands/">Uso de Comandos Slash</a> <a class="header-anchor" href="#uso-de-comandos-slash" aria-label="Permalink to &quot;[Uso de Comandos Slash](./commands/)&quot;">​</a></h3><p>Domina el uso de todos los comandos DCP: <code>/dcp context</code> para ver el estado del contexto, <code>/dcp stats</code> para ver estadísticas, <code>/dcp sweep</code> para activar manualmente la poda.</p></div><h2 id="ruta-de-aprendizaje" tabindex="-1">Ruta de Aprendizaje <a class="header-anchor" href="#ruta-de-aprendizaje" aria-label="Permalink to &quot;Ruta de Aprendizaje&quot;">​</a></h2><p>Recomendamos estudiar el contenido de este capítulo en el siguiente orden:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Estrategias de Poda Automática → Herramientas Impulsadas por LLM → Comandos Slash</span></span>
<span class="line"><span>           ↓                               ↓                              ↓</span></span>
<span class="line"><span>   Entender los Principios      Dominar la Poda Inteligente   Aprender Monitoreo y Depuración</span></span></code></pre></div><ol><li><strong>Primero aprende estrategias de poda automática</strong>: Esta es la base de DCP, entiende los principios de funcionamiento de las tres estrategias</li><li><strong>Luego aprende herramientas impulsadas por LLM</strong>: Después de comprender las estrategias automáticas, aprende capacidades más avanzadas de poda activa por parte de la IA</li><li><strong>Por último aprende comandos Slash</strong>: Domina los métodos de monitoreo y control manual para facilitar la depuración y optimización</li></ol><div class="tip custom-block"><p class="custom-block-title">Requisitos Previos</p><p>Antes de estudiar este capítulo, asegúrate de haber completado:</p><ul><li><a href="./../start/getting-started/">Instalación y Inicio Rápido</a> - Completa la instalación del plugin DCP</li><li><a href="./../start/configuration/">Guía de Configuración</a> - Entiende los conceptos básicos del sistema de configuración</li></ul></div><h2 id="siguientes-pasos" tabindex="-1">Siguientes Pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes Pasos&quot;">​</a></h2><p>Después de completar este capítulo, puedes continuar explorando:</p><ul><li><strong><a href="./../advanced/protection/">Mecanismos de Protección</a></strong> - Aprende cómo proteger el contenido crítico para que no sea podado por error</li><li><strong><a href="./../advanced/state-persistence/">Persistencia de Estado</a></strong> - Entiende cómo DCP preserva el estado entre sesiones</li><li><strong><a href="./../advanced/prompt-caching/">Impacto en el Cache de Prompt</a></strong> - Entiende los compromisos entre DCP y el Prompt Caching</li></ul>`,12)])])}const h=e(t,[["render",n]]);export{u as __pageData,h as default};
